def set_widths(sheet, widths, nrows):
    for idx, width in enumerate(widths):
        rng = sheet.get_range_by_indexes(0, idx, max(nrows, 1), 1)
        rng.format.column_width = width


def write_title(sheet, title, subtitle, ncols):
    end_col = col_letter(max(ncols, 1))
    if ncols > 1:
        sheet.merge_cells(f"A1:{end_col}1")
        sheet.merge_cells(f"A2:{end_col}2")
    sheet.get_range("A1").values = [[title]]
    sheet.get_range("A1").format = TITLE_STYLE
    sheet.get_range("A1").format.row_height = 28
    sheet.get_range("A2").values = [[subtitle]]
    sheet.get_range("A2").format = SUBTITLE_STYLE
    sheet.get_range("A2").format.row_height = 45


def write_table(sheet, title, subtitle, headers, rows, table_name, widths=None, start_row=4, body_height=54):
    # start_row is 1-based row for header
    ncols = len(headers)
    write_title(sheet, title, subtitle, ncols)
    matrix = [headers] + rows
    rng = sheet.get_range_by_indexes(start_row - 1, 0, len(matrix), ncols)
    rng.values = matrix
    header_rng = sheet.get_range_by_indexes(start_row - 1, 0, 1, ncols)
    header_rng.format = HEADER_STYLE
    header_rng.format.row_height = 36
    body_rng = sheet.get_range_by_indexes(start_row, 0, len(rows), ncols)
    body_rng.format = BODY_STYLE
    body_rng.format.row_height = body_height
    try:
        sheet.tables.add(rng, True, table_name)
    except Exception:
        # Keep content if table creation fails; do not break workbook build.
        pass
    try:
        sheet.freeze_panes.freeze_rows(start_row)
    except Exception:
        pass
    if widths is None:
        widths = [18] * ncols
    set_widths(sheet, widths, start_row + len(rows) + 3)
    return rng

