write_table(wb.worksheets.add("Flow Notes"), "Flow Notes by Care Setting", "Narrative summaries of how people enter/contact each setting, what is collected first, when tests happen, and where signals are lost.", flow_notes_headers, flow_notes, "FlowNotesTable", widths=[24,28,32,30,42,42,42,42,42,38,16], body_height=72)
write_table(wb.worksheets.add("Comparison"), "Comparison Table Across Settings", "Side-by-side comparison of entry, roles, data, decisions, referrals and follow-up patterns.", comparison_headers, comparison, "ComparisonTable", widths=[24,28,28,32,34,30,28,30,34,36,40], body_height=60)
write_table(wb.worksheets.add("Flow Maps"), "Flow Maps", "Stepwise text maps for major real-world patient flows. Arrows are intentionally concrete and operational rather than idealized.", flow_map_headers, flow_maps, "FlowMapsTable", widths=[10,24,22,60,36,34,38,38,42,42,16], body_height=78)
write_table(wb.worksheets.add("Stage Data Matrix"), "Data Collected at Each Stage", "Patient-stage matrix showing what data enters the workflow, who touches it, and which black zones are common at that stage.", stage_headers, stage_rows, "StageDataTable", widths=[22,44,34,36,42,42,42], body_height=66)
write_table(wb.worksheets.add("Findings Log"), "Tagged Findings Log", "Row-wise evidence log using the shared tagging fields. Facts and quotes are source-backed; product-design implications are interpretive notes.", finding_headers, findings, "FindingsTable", widths=[34,42,26,20,24,24,28,26,32,38,30,42,38,18,28,24,38,42,14,44,32], body_height=78)
write_table(wb.worksheets.add("Black Zones"), "Weak Points and Black Zones", "Failure patterns where important diagnostic signals are commonly lost. Each row links examples to design implications.", black_headers, black_rows, "BlackZonesTable", widths=[28,34,46,36,38,44,42,16], body_height=70)
write_table(wb.worksheets.add("Source Log"), "Source Log", "All source links used in the workbook. URLs are plain text for traceability.", ["Source ID","Source title","Source URL","Source type","Date published or accessed","Country/region","Care setting","Evidence quality","Notes and context"], sources, "SourceLogTable", widths=[10,42,50,26,24,24,26,14,52], body_height=58)
write_table(wb.worksheets.add("Taxonomy"), "Taxonomy / Allowed Tags", "User-supplied care-setting, stage and black-zone tags used to keep findings searchable.", tax_headers, tax_rows, "TaxonomyTable", widths=[24,36,60], body_height=28)

# Styling refinements: conditional formatting on evidence quality columns in Findings and Source Log, if supported.
try:
    fs = wb.worksheets.get_item("Findings Log")
    # Evidence quality column S (1-based 19, zero-based 18), rows 5 onward.
    eq_rng = fs.get_range_by_indexes(4, 18, len(findings), 1)
    eq_rng.conditional_formats.add_custom('=S5="high"', {"fill": "#D9EAD3"})
    eq_rng.conditional_formats.add_custom('=S5="medium"', {"fill": "#FFF2CC"})
    eq_rng.conditional_formats.add_custom('=S5="low"', {"fill": "#F4CCCC"})
except Exception:
    pass
try:
    ss = wb.worksheets.get_item("Source Log")
    eq_rng2 = ss.get_range_by_indexes(4, 7, len(sources), 1)
    eq_rng2.conditional_formats.add_custom('=H5="high"', {"fill": "#D9EAD3"})
    eq_rng2.conditional_formats.add_custom('=H5="medium"', {"fill": "#FFF2CC"})
    eq_rng2.conditional_formats.add_custom('=H5="low"', {"fill": "#F4CCCC"})
except Exception:
    pass

# Add data validation on evidence quality fields if supported.
try:
    fs = wb.worksheets.get_item("Findings Log")
    fs.get_range_by_indexes(4, 18, len(findings), 1).data_validation = {"rule": {"type": "list", "values": ["high", "medium", "low"]}}
    sl = wb.worksheets.get_item("Source Log")
    sl.get_range_by_indexes(4, 7, len(sources), 1).data_validation = {"rule": {"type": "list", "values": ["high", "medium", "low"]}}
except Exception:
    pass

# Freeze panes for all data sheets and set top row heights; table headers already styled.
for name in ["Flow Notes","Comparison","Flow Maps","Stage Data Matrix","Findings Log","Black Zones","Source Log","Taxonomy"]:
    try:
        sh = wb.worksheets.get_item(name)
        sh.freeze_panes.freeze_rows(4)
    except Exception:
        pass

# Compact verification output and export.
print("Created workbook with", len(findings), "findings and", len(sources), "sources.")
print("Top settings:", setting_counts.most_common(5))

# Export file
SpreadsheetFile.export_xlsx(wb).save(OUT)
print(OUT)
